26	QEMU_PLUGIN_EXPORT int qemu_plugin_version = QEMU_PLUGIN_VERSION;
27	
28	typedef struct {
29	    struct qemu_plugin_register *gpr[32];
30	    struct qemu_plugin_register *fpr[32];
31	    struct qemu_plugin_register *pc;
32	
33	    // M-mode CSRs as exposed by QEMU's gdbstub csr feature.
34	    struct qemu_plugin_register *mstatus;
35	    struct qemu_plugin_register *mepc;
36	    struct qemu_plugin_register *mtvec;
37	    struct qemu_plugin_register *mcause;
38	    struct qemu_plugin_register *mtval;
39	    struct qemu_plugin_register *mscratch;
40	    struct qemu_plugin_register *medeleg;
41	    struct qemu_plugin_register *mideleg;
42	    struct qemu_plugin_register *mip;
43	    struct qemu_plugin_register *mie;
44	    struct qemu_plugin_register *mcycle;
45	    struct qemu_plugin_register *minstret;
46	    struct qemu_plugin_register *satp;
47	
48	    struct qemu_plugin_register *pmpcfg[HYBRID_PMP_CFG_NUM];
49	    struct qemu_plugin_register *pmpaddr[HYBRID_PMP_ADDR_NUM];
50	
51	    struct qemu_plugin_register *vstart;
52	    struct qemu_plugin_register *vxsat;
53	    struct qemu_plugin_register *vxrm;
54	    struct qemu_plugin_register *vcsr;
55	    struct qemu_plugin_register *vtype;
56	    struct qemu_plugin_register *vl;
57	    struct qemu_plugin_register *vlenb;
58	    struct qemu_plugin_register *vreg[32];
59	
60	    // icount-trigger mode: per-vcpu retired-insn counter, incremented in
61	    // on_icount_tick. When icount_target is reached, the same drain path
62	    // as CSR/PC mode fires (on_handoff -> write_state_atomic -> exit 200).
63	    uint64_t icount_retired;
64	} VcpuRegs;
65	
66	static struct qemu_plugin_scoreboard *vcpu_state;
67	static char *outfile_path;
68	
69	// PC-trigger mode: when enter_pc_arg is non-zero (set via plugin arg
70	// `enter_pc=0x...`), the CSR-insn matcher is bypassed entirely and the
71	// drain callback is registered only for instructions whose vaddr equals
72	// enter_pc_arg. The kind reported on the drain is HYBRID_HANDOFF_ENTER
73	// (entry into vsim), matching CSR-mode `csrwi 0x7C0, 0` semantics.
74	static uint64_t enter_pc_arg;
75	static int pc_mode;
76	
77	// icount-trigger mode: when icount_target is non-zero (set via plugin arg
78	// `icount=N`), every translated insn gets an exec callback that bumps a
79	// per-vcpu counter; on threshold-cross the drain fires at that insn
80	// boundary. Coexists with CSR/PC modes - either trigger can win.
81	static uint64_t icount_target;
82	static int icount_mode;
83	
84	// BBV-emit mode (SimPoint profile): when bbv_mode is set (plugin args
85	// `bbv_out=PATH,slice=N`), every translated insn gets an exec callback
86	// that ticks a global BBV counter; one .bb row per N retired insns is
87	// flushed to PATH. Coexists with the drain triggers - independently
88	// registered before icount so that on co-firing (icount target == slice
89	// multiple) the slice row is emitted before exit(200).
90	static BbvEmit *bbv_emit;
91	static char    *bbv_out_path;
92	static uint64_t bbv_slice_target;
93	static int      bbv_mode;
94	
95	// Slice-consume mode (SimPoint replay; F11): when slice_consume_mode is
96	// set (plugin args `slice=N,slice_at=K`), the plugin counts slice
97	// boundaries (one boundary per N retired insns) and drains at the end
98	// of slice index K (0-based). With K=2 and slice=1000, drain fires at
99	// insn 3000 - the boundary that closes the third slice. The orchestrator
100	// chains one invocation per SimPoint cluster-representative slice idx.
101	// Shares the `slice=` parameter with BBV-emit; works independently of
102	// whether `bbv_out=` is also set.
103	static uint64_t slice_at_target;
104	static int      slice_consume_mode;
105	static uint64_t slice_consume_acc;
106	static uint64_t slice_consume_idx;
107	
108	// Drain-at-exit mode (F14): when drain_at_exit_mode is set (plugin arg
109	// `drain_at_exit=1`), the plugin registers a per-insn exec callback that
110	// bumps `atexit_insn_count`, and a `qemu_plugin_register_atexit_cb` that
111	// drains state on natural program exit (e.g. semihosting EXIT). The
112	// atexit callback overrides s.minstret with the plugin counter so the
113	// caller (./hsim estimate --icount 0) gets a true retired-insn count
114	// independent of QEMU's PMU semantics (which can return host ticks on
115	// system-mode without `-icount`). `drained_already` suppresses the
116	// atexit path if any other trigger (CSR/PC/icount/slice) drained first.
117	static int      drain_at_exit_mode;
118	static volatile int drained_already;
119	static uint64_t atexit_insn_count;
120	
121	static struct qemu_plugin_register *find_reg(GArray *regs, const char *name)
122	{
123	    for (guint i = 0; i < regs->len; i++) {
124	        qemu_plugin_reg_descriptor *rd =
125	            &g_array_index(regs, qemu_plugin_reg_descriptor, i);
126	        if (g_ascii_strcasecmp(rd->name, name) == 0) {
127	            return rd->handle;
128	        }
129	    }
130	    return NULL;
131	}
132	
133	// Lazily resolves register handles. The plugin's vcpu_init runs before
134	// QEMU has registered the dynamic gdb coprocessors (FPU, virtual, csr,
135	// vector), so qemu_plugin_get_registers() returns only the 33 core CPU
136	// regs at that moment. By the time the entry trigger fires, all dynamic
137	// features are registered and a fresh call returns the full list.
138	static void resolve_handles(VcpuRegs *v)
139	{
140	    g_autoptr(GArray) regs = qemu_plugin_get_registers();
141	    for (int i = 0; i < 32; i++) {
142	        v->gpr[i] = find_reg(regs, hybrid_gpr_names[i]);
143	        v->fpr[i] = find_reg(regs, hybrid_fpr_names[i]);
144	    }
145	    v->pc = find_reg(regs, "pc");
146	
147	    v->mstatus  = find_reg(regs, "mstatus");
148	    v->mepc     = find_reg(regs, "mepc");
149	    v->mtvec    = find_reg(regs, "mtvec");
150	    v->mcause   = find_reg(regs, "mcause");
151	    v->mtval    = find_reg(regs, "mtval");
152	    v->mscratch = find_reg(regs, "mscratch");
153	    v->medeleg  = find_reg(regs, "medeleg");
154	    v->mideleg  = find_reg(regs, "mideleg");
155	    v->mip      = find_reg(regs, "mip");
156	    v->mie      = find_reg(regs, "mie");
157	    v->mcycle   = find_reg(regs, "mcycle");
158	    v->minstret = find_reg(regs, "minstret");
159	    v->satp     = find_reg(regs, "satp");
160	
161	    char buf[16];
162	    for (int i = 0; i < HYBRID_PMP_CFG_NUM; i++) {
163	        g_snprintf(buf, sizeof(buf), "pmpcfg%d", i);
164	        v->pmpcfg[i] = find_reg(regs, buf);
165	    }
166	    for (int i = 0; i < HYBRID_PMP_ADDR_NUM; i++) {
167	        g_snprintf(buf, sizeof(buf), "pmpaddr%d", i);
168	        v->pmpaddr[i] = find_reg(regs, buf);
169	    }
170	
171	    v->vstart = find_reg(regs, "vstart");
172	    v->vxsat  = find_reg(regs, "vxsat");
173	    v->vxrm   = find_reg(regs, "vxrm");
174	    v->vcsr   = find_reg(regs, "vcsr");
175	    v->vtype  = find_reg(regs, "vtype");
176	    v->vl     = find_reg(regs, "vl");
177	    v->vlenb  = find_reg(regs, "vlenb");
178	    for (int i = 0; i < 32; i++) {
179	        g_snprintf(buf, sizeof(buf), "v%d", i);
180	        v->vreg[i] = find_reg(regs, buf);
181	    }
182	}
183	
184	static uint64_t read_reg64(struct qemu_plugin_register *h)
185	{
186	    if (!h) return 0;
187	    g_autoptr(GByteArray) buf = g_byte_array_new();
188	    int sz = qemu_plugin_read_register(h, buf);
189	    if (sz <= 0) return 0;
190	    uint64_t v = 0;
191	    memcpy(&v, buf->data, sz < 8 ? (size_t) sz : 8);
192	    return v;
193	}
194	
195	// Reads up to `dst_max` bytes from a register handle. Returns the byte
196	// count written (0 on failure or NULL handle). Used for vector regs whose
197	// width = vlenb bytes.
198	static size_t read_reg_bytes(struct qemu_plugin_register *h,
199	                             uint8_t *dst, size_t dst_max)
200	{
201	    if (!h || dst_max == 0) return 0;
202	    g_autoptr(GByteArray) buf = g_byte_array_new();
203	    int sz = qemu_plugin_read_register(h, buf);
204	    if (sz <= 0) return 0;
205	    size_t n = (size_t) sz < dst_max ? (size_t) sz : dst_max;
206	    memcpy(dst, buf->data, n);
207	    return n;
208	}
209	
210	// Atomic on POSIX: write to .tmp, fsync, rename.
211	static int write_state_atomic(const struct hybrid_state_v1 *s, const char *path)
212	{
213	    char tmp[PATH_MAX];
214	    g_snprintf(tmp, sizeof(tmp), "%s.tmp.%d", path, (int) getpid());
215	    int fd = open(tmp, O_WRONLY | O_CREAT | O_TRUNC, 0600);
216	    if (fd < 0) {
217	        perror("hybrid_handoff: open tmp");
218	        return -1;
219	    }
220	    ssize_t want = (ssize_t) sizeof(*s);
221	    ssize_t got = write(fd, s, sizeof(*s));
222	    if (got != want) {
223	        perror("hybrid_handoff: write");
224	        close(fd);
225	        unlink(tmp);
226	        return -1;
227	    }
228	    fsync(fd);
229	    close(fd);
230	    if (rename(tmp, path) != 0) {
231	        perror("hybrid_handoff: rename");
232	        unlink(tmp);
233	        return -1;
234	    }
235	    return 0;
236	}
237	
238	// Drain CPU state to outfile_path. pc is computed by the caller (from a
239	// HandoffSite for trigger paths, or 0 for the atexit path which lacks an
240	// insn context). If minstret_override is non-zero, it replaces QEMU's PMU
241	// minstret in the state file (used by drain_at_exit mode to record a
242	// plugin-counted retired-insn total). Does NOT call exit -- caller
243	// decides exit(200) (normal trigger) vs _exit(200) (inside atexit chain).
244	static void drain_state_to_file(unsigned int vcpu_idx, uint64_t pc,
245	                                uint64_t minstret_override)
246	{
247	    VcpuRegs *v = qemu_plugin_scoreboard_find(vcpu_state, vcpu_idx);
248	    resolve_handles(v);
249	    struct hybrid_state_v1 s = {0};
250	    s.magic   = HYBRID_STATE_MAGIC;
251	    s.version = HYBRID_STATE_VERSION;
252	    s.flags   = HYBRID_FLAG_RV64;
253	    s.hart_id = vcpu_idx;
254	    s.priv    = 3;
255	    s.pc      = pc;
256	    for (int i = 0; i < 32; i++) s.gpr[i] = read_reg64(v->gpr[i]);
257	
258	    // Floating-point: only set FP flag if at least one handle was bound,
259	    // i.e. QEMU advertised the FPU feature (D extension).
260	    int has_fp = 0;
261	    for (int i = 0; i < 32; i++) {
262	        s.fpr[i] = read_reg64(v->fpr[i]);
263	        if (v->fpr[i]) has_fp = 1;
264	    }
265	    if (has_fp) s.flags |= HYBRID_FLAG_FP;
266	
267	    s.mstatus  = read_reg64(v->mstatus);
268	    s.mepc     = read_reg64(v->mepc);
269	    s.mtvec    = read_reg64(v->mtvec);
270	    s.mcause   = read_reg64(v->mcause);
271	    s.mtval    = read_reg64(v->mtval);
272	    s.mscratch = read_reg64(v->mscratch);
273	    s.medeleg  = read_reg64(v->medeleg);
274	    s.mideleg  = read_reg64(v->mideleg);
275	    s.mip      = read_reg64(v->mip);
276	    s.mie      = read_reg64(v->mie);
277	    s.mcycle   = read_reg64(v->mcycle);
278	    s.minstret = minstret_override ? minstret_override
279	                                   : read_reg64(v->minstret);
280	    s.satp     = read_reg64(v->satp);
281	
282	    for (int i = 0; i < HYBRID_PMP_CFG_NUM; i++)
283	        s.pmpcfg[i] = read_reg64(v->pmpcfg[i]);
284	    for (int i = 0; i < HYBRID_PMP_ADDR_NUM; i++)
285	        s.pmpaddr[i] = read_reg64(v->pmpaddr[i]);
286	
287	    // Vector: only set V flag if QEMU advertised the V extension. vlenb
288	    // bounds the per-register byte count copied into vreg[].
289	    s.vstart = read_reg64(v->vstart);
290	    s.vxsat  = read_reg64(v->vxsat);
291	    s.vxrm   = read_reg64(v->vxrm);
292	    s.vcsr   = read_reg64(v->vcsr);
293	    s.vtype  = read_reg64(v->vtype);
294	    s.vl     = read_reg64(v->vl);
295	    s.vlenb  = read_reg64(v->vlenb);
296	    if (v->vlenb && s.vlenb > 0) {
297	        s.flags |= HYBRID_FLAG_V;
298	        size_t bytes = s.vlenb < HYBRID_VLEN_BYTES_MAX
299	                     ? (size_t) s.vlenb
300	                     : (size_t) HYBRID_VLEN_BYTES_MAX;
301	        for (int i = 0; i < 32; i++)
302	            (void) read_reg_bytes(v->vreg[i],
303	                                  &s.vreg[(size_t) i * HYBRID_VLEN_BYTES_MAX],
304	                                  bytes);
305	    }
306	
307	    if (write_state_atomic(&s, outfile_path) != 0) {
308	        fprintf(stderr, "hybrid_handoff: failed to write state file\n");
309	        exit(2);
310	    }
311	    fprintf(stderr,
312	            "hybrid_handoff: drained state to %s (pc=%#" PRIx64 "), exiting\n",
313	            outfile_path, s.pc);
314	}
315	
316	static void on_handoff(unsigned int vcpu_idx, void *udata)
317	{
318	    const HandoffSite *site = (const HandoffSite *) udata;
319	    if (site->kind != HYBRID_HANDOFF_ENTER) return;
320	    // F14: suppress the atexit drain path now that we have a real trigger.
321	    drained_already = 1;
322	    // PC via translation-time vaddr+size; reading the gdbstub PC inside the
323	    // exec callback can lag the actual current insn when V instructions
324	    // retire just before the trigger (TCG defers PC writes for performance).
325	    drain_state_to_file(vcpu_idx, compute_handoff_pc(site), 0);
326	    // 200 == kExitHandoffToQemu in verilator/src/hybrid/exit_codes.hpp.
327	    // Distinguishes drain from workload completion (0) so the orchestrator
328	    // can decide the next spawn.
329	    exit(200);
330	}
331	
332	// F14: per-insn tick. Increments a global counter every retired insn so the
333	// drain-at-exit path can report a true retired-insn total (independent of
334	// QEMU's PMU semantics).
335	static void on_count_tick(unsigned int vcpu_idx, void *udata)
336	{
337	    (void) vcpu_idx;
338	    (void) udata;
339	    atexit_insn_count++;
340	}
341	
342	// F14: atexit drain. Fires when QEMU exits naturally (e.g. guest semihosting
343	// EXIT). The semihosting EXIT runs on the vCPU thread, so current_cpu is
344	// still set and qemu_plugin_read_register works. If any other trigger
345	// already drained, return immediately (drained_already guards against
346	// double drain). Inside an atexit handler, exit() is UB per C11 7.22.4.4;
347	// use _exit() to skip the rest of the atexit chain.
348	static void on_atexit(qemu_plugin_id_t id, void *udata)
349	{
350	    (void) id;
351	    (void) udata;
352	    if (drained_already) return;
353	    if (!drain_at_exit_mode) return;
354	    // pc=0 is a positive marker that the atexit path drained (no trigger).
355	    drain_state_to_file(0, 0, atexit_insn_count);
356	    fflush(stderr);
357	    _exit(200);
358	}
359	
360	// Per-insn tick for icount mode. udata is the per-insn HandoffSite
361	// pre-allocated at translation time, so on_handoff's compute_handoff_pc
362	// returns the lag-free post-trigger PC (same property as the CSR path).
363	static void on_icount_tick(unsigned int vcpu_idx, void *udata)
364	{
365	    VcpuRegs *v = qemu_plugin_scoreboard_find(vcpu_state, vcpu_idx);
366	    if (++v->icount_retired < icount_target) return;
367	    on_handoff(vcpu_idx, udata);
368	}
369	
370	// Per-insn tick for BBV-emit mode. udata is the bb_id (1-based) cast to
371	// pointer; that mapping is stable across calls because bbv_emit_assign_id
372	// is hashed by TB-start PC. The tick attributes one insn to the bb_id and
373	// flushes a slice row when the per-slice counter saturates.
374	static void on_bbv_tick(unsigned int vcpu_idx, void *udata)
375	{
376	    (void) vcpu_idx;
377	    uint64_t bb_id = (uint64_t) GPOINTER_TO_UINT(udata);
378	    bbv_emit_tick(bbv_emit, bb_id);
379	}
380	
381	// Per-insn tick for slice-consume mode (F11). Counts insns into the
382	// slice accumulator; on each slice boundary increments slice_consume_idx
383	// and resets the accumulator. Once slice_consume_idx exceeds the target
384	// slice index, drains via on_handoff at that same insn boundary. udata
385	// is the per-insn HandoffSite (allocated at translation time) so the
386	// post-trigger PC reaches on_handoff lag-free.
387	static void on_slice_consume_tick(unsigned int vcpu_idx, void *udata)
388	{
389	    if (++slice_consume_acc < bbv_slice_target) return;
390	    slice_consume_acc = 0;
391	    if (slice_consume_idx++ < slice_at_target) return;
392	    // After the post-increment above, slice_consume_idx == slice_at_target+1
393	    // (the count of fully retired slices). Log so the e2e test can verify
394	    // drain timing without relying on minstret (which is a cycle-counter
395	    // proxy on andes-ax45mpv and does not track plugin-counted insns).
396	    fprintf(stderr,
397	            "hybrid_handoff: slice-consume drain (idx=%" PRIu64
398	            " target=%" PRIu64 ")\n",
399	            slice_consume_idx, slice_at_target);
400	    on_handoff(vcpu_idx, udata);

