17	
18	class StateDrain
19	{
20	public:
21	  using RD = ResumeDriver;
22	
23	  explicit StateDrain(DmiBus& bus)
24	      : bus_{bus}
25	  {}
26	
27	  // Drain x1..x31 + PC. FP/CSR/V slots remain zero; merge them in via
28	  // drain_with_passthrough when the QEMU 1 snapshot is available.
29	  auto drain() -> hybrid_state_v1
30	  {
31	    bus_.write(RD::kDmcontrol, RD::kDmcontrolDmactive);
32	    bus_.write(RD::kDmcontrol, RD::kDmcontrolDmactive | RD::kDmcontrolHaltreq);
33	    poll_until_set(bus_, RD::kDmstatus, RD::kDmstatusAllhalted,
34	                   "StateDrain halt");
35	
36	    hybrid_state_v1 state{};
37	    state.magic   = HYBRID_STATE_MAGIC;
38	    state.version = HYBRID_STATE_VERSION;
39	    state.flags   = HYBRID_FLAG_RV64;
40	    state.priv    = 3;
41	
42	    for (uint16_t i = 1; i < 32; ++i)
43	      state.gpr[i] = read_64bit_register(regno_gpr(i));
44	
45	    state.pc = read_64bit_register(regno_csr(RD::kCsrDpc));
46	    return state;
47	  }
48	
49	  // Returns the input snapshot with x1..x31 and PC overwritten by a fresh
50	  // DM read. When HYBRID_FLAG_FP is set, also freshly reads f0..f31 so
51	  // post-vsim FP modifications are captured (otherwise the stale QEMU 1
52	  // snapshot leaks through to QEMU 2). When HYBRID_FLAG_V is set, also
53	  // freshly reads the six V CSRs (vstart/vxsat/vxrm/vcsr/vtype/vl); vlenb
54	  // and vreg remain pass-through (read-only / too large for DM).
55	  // mcycle/minstret are always refreshed (F-T2.4): the vsim phase's
56	  // contribution would otherwise be discarded as the passthrough preserves
57	  // QEMU1's pre-handoff value.
58	  auto drain_with_passthrough(const hybrid_state_v1& input) -> hybrid_state_v1
59	  {
60	    auto state       = input;
61	    const auto fresh = drain();
62	    std::copy(std::begin(fresh.gpr) + 1, std::end(fresh.gpr),
63	              std::begin(state.gpr) + 1);
64	    state.pc = fresh.pc;
65	
66	    if (input.flags & HYBRID_FLAG_FP) {
67	      for (uint16_t i = 0; i < 32; ++i)
68	        state.fpr[i] = read_64bit_register(regno_fpr(i));
69	    }
70	
71	    if (input.flags & HYBRID_FLAG_V) {
72	      state.vstart = read_64bit_register(regno_csr(RD::kCsrVstart));
73	      state.vxsat  = read_64bit_register(regno_csr(RD::kCsrVxsat));
74	      state.vxrm   = read_64bit_register(regno_csr(RD::kCsrVxrm));
75	      state.vcsr   = read_64bit_register(regno_csr(RD::kCsrVcsr));
76	      state.vtype  = read_64bit_register(regno_csr(RD::kCsrVtype));
77	      state.vl     = read_64bit_register(regno_csr(RD::kCsrVl));
78	    }
79	
80	    state.mcycle   = read_64bit_register(regno_csr(RD::kCsrMcycle));
81	    state.minstret = read_64bit_register(regno_csr(RD::kCsrMinstret));
82	
83	    return state;
84	  }
85	
86	private:
87	  auto read_64bit_register(uint16_t regno) -> uint64_t
88	  {
89	    bus_.write(RD::kCommand, access_register_command(regno, AarSize::Bits64,
90	                                                     /*write=*/false));
91	    poll_until_clear(bus_, RD::kAbstractcs, RD::kAbstractcsBusy,
92	                     "StateDrain read_register");
93	    // If the hardware DM does not implement Abstract access for this
94	    // register, cmderr is set sticky and DATA0/DATA1 hold stale bytes.
95	    // Clear the error and report 0 for that field so the next read can
96	    // proceed - a missing CSR mirrors as zero rather than corrupting the
97	    // adjacent slot.
98	    const auto status = bus_.read(RD::kAbstractcs);
99	    if ((status & RD::kAbstractcsCmderrMask) != 0u) {
100	      bus_.write(RD::kAbstractcs, RD::kAbstractcsCmderrMask);
101	      return 0u;
102	    }
103	    const uint64_t lo = bus_.read(RD::kData0);
104	    const uint64_t hi = bus_.read(RD::kData1);
105	    return lo | (hi << 32);
106	  }
107	
108	  DmiBus& bus_;
109	};
