3	#define N 32
4	
5	static float A[N][N];
6	static float B[N][N];
7	static float C[N][N];
8	
9	static void init(void) {
10	    for (int i = 0; i < N; i++) {
11	        for (int j = 0; j < N; j++) {
12	            A[i][j] = (float)(i + j);
13	            B[i][j] = (float)(i - j);
14	            C[i][j] = 0.0f;
15	        }
16	    }
17	}
18	
19	static void gemm(void) {
20	    for (int i = 0; i < N; i++) {
21	        for (int k = 0; k < N; k++) {
22	            float a = A[i][k];
23	            for (int j = 0; j < N; j++) {
24	                C[i][j] += a * B[k][j];
25	            }
26	        }
27	    }
28	}
29	
30	int main(void) {
31	    init();
32	    gemm();
33	    printf("C[0][0]=%f C[N-1][N-1]=%f\n", C[0][0], C[N-1][N-1]);
34	    return 0;
35	}
